
; Petmate9 Horizontal Smooth Scroller (C64) — Double Buffered
; Source: c64-4xwidth (160x25), scroll 120 cols
; Buffer A = $0400, Buffer B = $0C00 — swap via $D018 in IRQ
!include "macros.asm"



!let irq_top_line  = 1
!let debug_build   = FALSE
!let VISIBLE_COLS  = 40
!let VISIBLE_ROWS  = 25
!let MAX_SCROLL    = 120
!let SRC_ROW_WIDTH = 160
!let SCROLL_SPEED  = 1
!let D018_A        = $15
!let D018_B        = $35

!let zp_src        = $20
!let zp_dst        = $22
!let zp_vis_row    = $24
!let zp_col_lo     = $25   ; scrollCol low byte for source offset
!let zp_col_hi     = $26   ; scrollCol high byte (always 0 for col<256)

+basic_start(entry)

;--------------------------------------------------------------
; Entry
;--------------------------------------------------------------
entry: {



    sei
    lda #$35
    sta $01
    +setup_irq(irq_top, irq_top_line)
    cli

    ; Border / background
    lda #14
    sta $d020
    lda #6
    sta $d021

    ; Init scroll state
    lda #7
    sta scrollFine
    lda #0
    sta scrollCol
    sta displayBuf
    sta workBufOffset
    lda #SCROLL_SPEED
    sta delayCounter

    ; Pre-fill BOTH buffers so the first swap is already ready
    ; Buffer A (workBufOffset=0)
    jsr copy_window_screen
    jsr copy_window_color
    ; Buffer B (workBufOffset=8)
    lda #$08
    sta workBufOffset
    jsr copy_window_screen
    lda #$00
    sta workBufOffset

    ; Set VIC: 25 rows, YSCROLL=3 (normal), 38 cols, XSCROLL=7
    lda #$1b            ; 25-row mode, normal
    sta $d011
    lda #$c7            ; 38-col mode ($C0) + XSCROLL=7
    sta nextD016
    sta $d016
    lda #D018_A
    sta nextD018
    sta $d018

    ; ── Main loop: double-buffered prepare-ahead ──

main_loop:
    lda vsyncFlag
    beq main_loop
    lda #0
    sta vsyncFlag

    dec delayCounter
    bne main_loop
    lda #SCROLL_SPEED
    sta delayCounter

    ; ── Prepare next scroll step ──
    dec scrollFine
    bpl prep_fine

    ; Coarse scroll needed
    lda #7
    sta scrollFine

    inc scrollCol
    lda scrollCol
    cmp #MAX_SCROLL
    bcc do_coarse
    ; Wrap
    lda #0
    sta scrollCol

do_coarse:
    ; Determine work-buffer offset
    lda displayBuf
    bne work_is_a
    lda #$08
    jmp set_work
work_is_a:
    lda #$00
set_work:
    sta workBufOffset

    ; Copy 25 rows × 40 cols from source to work buffer (invisible)
    jsr copy_window_screen
    ; Copy 25 rows × 40 cols to $D800
    jsr copy_window_color

    ; Queue buffer swap
    lda displayBuf
    eor #1
    sta displayBuf
    beq swap_a
    lda #D018_B
    jmp queue_swap
swap_a:
    lda #D018_A
queue_swap:
    sta nextD018

prep_fine:
    lda #$c0            ; 38-col mode
    ora scrollFine
    sta nextD016
    jmp main_loop
}

;--------------------------------------------------------------
; copy_window_screen – extract 40-col strip from 160-col source
;   Reads from src_scr_row_base[row] + scrollCol
;   Writes to screen_dest[row] + workBufOffset
;--------------------------------------------------------------
copy_window_screen: {
    lda scrollCol
    sta zp_col_lo
    lda #0
    sta zp_col_hi       ; scrollCol < 256, but carry may bump hi
    sta zp_vis_row

row_loop:
    ldx zp_vis_row
    ; Source = src_scr_row_base + scrollCol
    lda src_scr_row_lo,x
    clc
    adc zp_col_lo
    sta zp_src
    lda src_scr_row_hi,x
    adc zp_col_hi
    sta zp_src+1

    ; Dest = screen_dest + workBufOffset
    lda screen_dest_lo,x
    sta zp_dst
    lda screen_dest_hi,x
    clc
    adc workBufOffset
    sta zp_dst+1

    jsr copy_row

    inc zp_vis_row
    lda zp_vis_row
    cmp #VISIBLE_ROWS
    bne row_loop
    rts
}

;--------------------------------------------------------------
; copy_window_color – extract 40-col strip to $D800
;--------------------------------------------------------------
copy_window_color: {
    lda scrollCol
    sta zp_col_lo
    lda #0
    sta zp_col_hi
    sta zp_vis_row

row_loop:
    ldx zp_vis_row
    lda src_col_row_lo,x
    clc
    adc zp_col_lo
    sta zp_src
    lda src_col_row_hi,x
    adc zp_col_hi
    sta zp_src+1

    lda color_dest_lo,x
    sta zp_dst
    lda color_dest_hi,x
    sta zp_dst+1

    jsr copy_row

    inc zp_vis_row
    lda zp_vis_row
    cmp #VISIBLE_ROWS
    bne row_loop
    rts
}

;--------------------------------------------------------------
; copy_row – copy VISIBLE_COLS (40) bytes from (zp_src) to (zp_dst)
;--------------------------------------------------------------
copy_row: {
    ldy #VISIBLE_COLS-1
loop:
    lda (zp_src),y
    sta (zp_dst),y
    dey
    bpl loop
    rts
}

;--------------------------------------------------------------
; Raster IRQ — applies $D016 + $D018 at fixed raster position
;--------------------------------------------------------------
irq_top: {
    +irq_start(end)

    lda nextD016
    sta $d016
    lda nextD018
    sta $d018

    lda #1
    sta vsyncFlag

!if (debug_build) {
    inc $d020
}

!if (debug_build) {
    dec $d020
}
    +irq_end(irq_top, irq_top_line)
end:
}

;--------------------------------------------------------------
; Variables
;--------------------------------------------------------------
vsyncFlag:      !byte 0
nextD016:       !byte $c7    ; 38-col + XSCROLL=7
nextD018:       !byte D018_A
scrollFine:     !byte 7
scrollCol:      !byte 0
delayCounter:   !byte 1
displayBuf:     !byte 0
workBufOffset:  !byte 0

;--------------------------------------------------------------
; Row address tables
;--------------------------------------------------------------
; Source screen row BASES (25 entries, each row 160 bytes wide)
src_scr_row_lo: !byte $00,$A0,$40,$E0,$80,$20,$C0,$60,$00,$A0,$40,$E0,$80,$20,$C0,$60,$00,$A0,$40,$E0,$80,$20,$C0,$60,$00
src_scr_row_hi: !byte $20,$20,$21,$21,$22,$23,$23,$24,$25,$25,$26,$26,$27,$28,$28,$29,$2A,$2A,$2B,$2B,$2C,$2D,$2D,$2E,$2F
; Source color row BASES
src_col_row_lo: !byte $A0,$40,$E0,$80,$20,$C0,$60,$00,$A0,$40,$E0,$80,$20,$C0,$60,$00,$A0,$40,$E0,$80,$20,$C0,$60,$00,$A0
src_col_row_hi: !byte $2F,$30,$30,$31,$32,$32,$33,$34,$34,$35,$35,$36,$37,$37,$38,$39,$39,$3A,$3A,$3B,$3C,$3C,$3D,$3E,$3E
; Dest screen rows (relative to $0400, workBufOffset adds $08 for $0C00)
screen_dest_lo: !byte $00,$28,$50,$78,$A0,$C8,$F0,$18,$40,$68,$90,$B8,$E0,$08,$30,$58,$80,$A8,$D0,$F8,$20,$48,$70,$98,$C0
screen_dest_hi: !byte $04,$04,$04,$04,$04,$04,$04,$05,$05,$05,$05,$05,$05,$06,$06,$06,$06,$06,$06,$06,$07,$07,$07,$07,$07
; Dest color rows ($D800)
color_dest_lo: !byte $00,$28,$50,$78,$A0,$C8,$F0,$18,$40,$68,$90,$B8,$E0,$08,$30,$58,$80,$A8,$D0,$F8,$20,$48,$70,$98,$C0
color_dest_hi: !byte $D8,$D8,$D8,$D8,$D8,$D8,$D8,$D9,$D9,$D9,$D9,$D9,$D9,$DA,$DA,$DA,$DA,$DA,$DA,$DA,$DB,$DB,$DB,$DB,$DB




;--------------------------------------------------------------
; Source data (uncompressed, 160 cols × 25 rows)
;--------------------------------------------------------------
* = $2000
screen_data:

!byte $5B,$40,$40,$40,$5B,$40,$40,$40,$5B,$40,$40,$40,$5B,$40,$40,$40,$5B,$40,$40,$40,$5B,$40,$40,$40,$5B,$40,$40,$40,$5B,$40,$40,$40,$5B,$40,$40,$40,$5B,$40,$40,$40,$5B,$40,$40,$40,$5B,$40,$40,$40,$5B,$40,$40,$40,$5B,$40,$40,$40,$5B,$40,$40,$40,$5B,$40,$40,$40,$5B,$40,$40,$40,$5B,$40,$40,$40,$5B,$40,$40,$40,$5B,$40,$40,$40,$5B,$40,$40,$40,$5B,$40,$40,$40,$5B,$40,$40,$40,$5B,$40,$40,$40,$5B,$40,$40,$40,$5B,$40,$40,$40,$5B,$40,$40,$40,$5B,$40,$40,$40,$5B,$40,$40,$40,$5B,$40,$40,$40,$5B,$40,$40,$40,$5B,$40,$40,$40,$5B,$40,$40,$40,$5B,$40,$40,$40,$5B,$40,$40,$40,$5B,$40,$40,$40,$5B,$40,$40,$40,$5B,$40,$40,$40,$5B,$40,$40,$40,$5B,$40,$40,$40
